import { useContext, useEffect, useState } from "react";
import { AuthContext } from "./AuthContext";
import { useNavigate } from "react-router-dom";

function Dashboard() {
    const [threads, setThreads] = useState([]);
    const [news, setNews] = useState([]);
    const [matches, setMatches] = useState([]);
    const [events, setEvents] = useState([]);
    const [windowWidth, setWindowWidth] = useState(window.innerWidth);
    const [modalOpen, setModalOpen] = useState(false);
    const [modalType, setModalType] = useState(""); // "Thread", "News", "Match", "Event"
    const [formData, setFormData] = useState({ title: "", content: "" });
    const navigate = useNavigate();
    const { user } = useContext(AuthContext);

    useEffect(() => {
        fetch("/api/threads").then(res => res.json()).then(setThreads);
        fetch("/api/news").then(res => res.json()).then(setNews);
        fetch("/api/matches").then(res => res.json()).then(data => {
            if (Array.isArray(data)) setMatches(data);
            else if (data.content) setMatches(data.content);
            else setMatches([]);
        }).catch(() => setMatches([]));
        fetch("/api/events").then(res => res.json()).then(setEvents);

        function handleResize() {
            setWindowWidth(window.innerWidth);
        }
        window.addEventListener("resize", handleResize);
        return () => window.removeEventListener("resize", handleResize);
    }, []);

    const hideThreads = windowWidth < 1000;
    const hideEvents = windowWidth < 800;

    const newsWidth = hideThreads ? (hideEvents ? "70%" : "50%") : "40%";
    const matchesWidth = hideThreads ? (hideEvents ? "30%" : "25%") : "20%";
    const threadsWidth = "20%";
    const eventsWidth = hideThreads ? "25%" : "20%";

    const headNews = news.length > 0 ? news[0] : null;
    const otherNews = news.length > 1 ? news.slice(1) : [];

    const openModal = (type) => {
        setModalType(type);
        setFormData({ title: "", content: "" });
        setModalOpen(true);
    };

    const submitModal = () => {
        const newItem = { ...formData };

        switch (modalType) {
            case "Thread":
                setThreads([newItem, ...threads]);
                break;
            case "News":
                setNews([newItem, ...news]);
                break;
            case "Match":
                setMatches([newItem, ...matches]);
                break;
            case "Event":
                setEvents([newItem, ...events]);
                break;
            default:
                break;
        }

        setModalOpen(false);
    };

    return (
        <main style={styles.Dashboard}>
            <div style={styles.container}>
                <div style={styles.flexRow}>
                    {!hideThreads && (
                        <div style={{ width: threadsWidth }}>
                            <h3>Threads</h3>
                            {user?.role === "admin" && (
                                <button style={styles.addBtn} onClick={() => openModal("Thread")}>
                                    Add Thread
                                </button>
                            )}
                            {threads.map((thread, idx) => (
                                <div
                                    style={styles.Threads}
                                    key={idx}
                                    onClick={() => navigate(`/thread/${idx}`)}
                                >
                                    {thread.title}
                                </div>
                            ))}
                        </div>
                    )}

                    <div style={{ width: newsWidth }}>
                        <h3>News</h3>
                        {user?.role === "admin" && (
                            <button style={styles.addBtn} onClick={() => openModal("News")}>
                                Add News
                            </button>
                        )}
                        {headNews && (
                            <div
                                style={styles.HeadNews}
                                onClick={() => alert(`Clicked head news: ${headNews.title || headNews.headline}`)}
                            >
                                {headNews.imageUrl && (
                                    <img
                                        src={headNews.imageUrl}
                                        alt={headNews.title || headNews.headline}
                                        style={styles.HeadNewsImage}
                                    />
                                )}
                                <div style={styles.HeadNewsOverlay}>
                                    <h4 style={{ margin: 0 }}>{headNews.title || headNews.headline}</h4>
                                </div>
                            </div>
                        )}
                        {otherNews.map((item, idx) => (
                            <div
                                key={idx}
                                onClick={() => alert(`Clicked news: ${item.title || item.headline}`)}
                                style={styles.News}
                            >
                                {item.title || item.headline}
                            </div>
                        ))}
                    </div>

                    <div style={{ width: matchesWidth }}>
                        <h3>Matches</h3>
                        {user?.role === "admin" && (
                            <button style={styles.addBtn} onClick={() => openModal("Match")}>
                                Add Match
                            </button>
                        )}
                        {matches.map((match, idx) => (
                            <div
                                key={idx}
                                onClick={() => alert(`Clicked match: ${match.teama} vs ${match.teamb}`)}
                                style={styles.Matches}
                            >
                                {match.teama} vs {match.teamb} <br />
                                {match.match_time && (
                                    <small>{new Date(match.match_time).toLocaleString()}</small>
                                )}
                            </div>
                        ))}
                    </div>

                    {!hideEvents && (
                        <div style={{ width: eventsWidth }}>
                            <h3>Events</h3>
                            {user?.role === "admin" && (
                                <button style={styles.addBtn} onClick={() => openModal("Event")}>
                                    Add Event
                                </button>
                            )}
                            {events.map((event, idx) => (
                                <div
                                    key={idx}
                                    onClick={() => alert(`Clicked event: ${event.title || event.name}`)}
                                    style={styles.Events}
                                >
                                    {event.title || event.name} <br />
                                    {event.event_date_time && (
                                        <small>{new Date(event.event_date_time).toLocaleString()}</small>
                                    )}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            {/* Modal */}
            {modalOpen && (
                <div style={styles.modalBackdrop}>
                    <div style={styles.modal}>
                        <h3>Add {modalType}</h3>
                        <input
                            placeholder="Title"
                            value={formData.title}
                            onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                            style={styles.modalInput}
                        />
                        <textarea
                            placeholder="Content / Description"
                            value={formData.content}
                            onChange={(e) => setFormData({ ...formData, content: e.target.value })}
                            style={styles.modalTextarea}
                        />
                        <button onClick={submitModal} style={styles.addBtn}>Submit</button>
                        <button onClick={() => setModalOpen(false)} style={{...styles.addBtn, marginLeft: "10px"}}>Cancel</button>
                    </div>
                </div>
            )}
        </main>
    );
}

const boxBase = {
    border: "1px solid #ccc",
    padding: "10px",
    marginBottom: "10px",
    borderRadius: "4px",
    cursor: "pointer",
    height: "40px",
    display: "flex",
    alignItems: "center",
    backgroundColor: "#fff",
    transition: "transform 0.3s ease, box-shadow 0.3s ease, background-color 0.3s ease",
    boxShadow: "0 2px 6px rgba(0,0,0,0.1)",
};

const styles = {
    Dashboard: { paddingTop: "60px", height: "100vh", backgroundColor: "gray" },
    container: { maxWidth: "1200px", margin: "0 auto", padding: "0 20px", height: "100%", backgroundColor: "#D50032" },
    flexRow: { display: "flex", gap: "20px", height: "calc(100% - 20px)" },
    Threads: { ...boxBase },
    News: { ...boxBase, backgroundColor: "#f9f9f9" },
    Matches: { ...boxBase, backgroundColor: "#f9f9f9" },
    Events: { ...boxBase, backgroundColor: "#f9f9f9" },
    HeadNews: { position: "relative", width: "100%", height: "150px", marginBottom: "15px", borderRadius: "6px", overflow: "hidden", boxShadow: "0 4px 10px rgba(0,0,0,0.2)", cursor: "pointer" },
    HeadNewsImage: { width: "100%", height: "100%", objectFit: "cover" },
    HeadNewsOverlay: { position: "absolute", bottom: 0, left: 0, right: 0, background: "rgba(0,0,0,0.6)", color: "#fff", padding: "8px 10px", fontSize: "1rem" },
    addBtn: { margin: "10px 0px", padding: "5px 10px", fontSize: "0.8rem", borderRadius: "4px", backgroundColor: "#041E42", color: "#D50032", border: "1px solid #D50032", cursor: "pointer", fontFamily: "garamond" },
    modalBackdrop: { position: "fixed", top:0, left:0, right:0, bottom:0, backgroundColor: "rgba(0,0,0,0.5)", display:"flex", justifyContent:"center", alignItems:"center" },
    modal: { backgroundColor: "#fff", padding:"20px", borderRadius:"6px", width:"300px", display:"flex", flexDirection:"column", gap:"10px" },
    modalInput: { padding:"5px", fontSize:"1rem" },
    modalTextarea: { padding:"5px", fontSize:"1rem", minHeight:"60px" },
};

export default Dashboard;
